"use strict";parserFactory.register("vipnovel.com",()=>new VipNovelParser);class VipNovelParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("li.wp-manga-chapter a")].map(e=>util.hyperLinkToChapter(e)).reverse()}findContent(e){return e.querySelector("div.reading-content")}extractTitleImpl(e){let t=e.querySelector("div.post-title h1, div.post-title h3");return util.removeChildElementsMatchingSelector(t,"span.hot"),t}extractAuthor(e){let t=e.querySelector("div.author-content a");return null===t?super.extractAuthor(e):t.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.summary_image")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.summary_content, div.summary__content")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"#init-links")}}